body:
Add support for two Chisel APIs which have wide adoption/use:

  1. [`loadMemoryFromFile`](https://javadoc.io/doc/edu.berkeley.cs/chisel3_2.13/latest/chisel3/util/experimental/loadMemoryFromFile$.html)
  2. [`loadMemoryFromFileInline`](https://javadoc.io/doc/edu.berkeley.cs/chisel3_2.13/latest/chisel3/util/experimental/loadMemoryFromFileInline$.html)

These are used to generate `$readmemh` or `$readmemb` for a memory with one of two different styles. (1) creates a bound module and does the initialization via an XMR. (2) puts the `$readmem*` in the same module as the memory.

This PR needs some polishing before it lands. However, I'm opening this to get some feedback early. Known ideas/improvements:

  - [ ] This needs more tests of the individual transforms that are handling the new attributes.
  - [ ] The `isBinary` and usage of booleans is kind of clunky. This could use `sv::MemBaseTypeAttr`.
  - [ ] This does a bunch of work to generate the "mangled" memory name. I actually think this is all dead code now?
  - [x] There are not checks that names/symbols being created in the outer Module are actually unique.
  - [x] The files for the `loadMemoryFromFile` path do not match the SFC outputs. This puts the bind and the bound module in the same file.

## Example

Consider the following Chisel code which will generate Verilog twice. Once using the (1) API and once using the (2) API.

```scala
//> using scala "2.13.10"
//> using lib "edu.berkeley.cs::chisel3::3.6.0-M2"
//> using plugin "edu.berkeley.cs:::chisel3-plugin::3.6.0-M2"

import chisel3._
import chisel3.util.experimental.{loadMemoryFromFile, loadMemoryFromFileInline}

class Read extends Bundle {
  val en = Input(Bool())
  val data = Output(UInt(8.W))
  val addr = Input(UInt(5.W))
}

class Write extends Bundle {
  val en = Input(Bool())
  val data = Input(UInt(8.W))
  val addr = Input(UInt(5.W))
}

object Style {
  sealed trait Type
  object Inline extends Type
  object Outline extends Type
}

class Foo(style: Style.Type) extends Module {
  val read = IO(new Read)
  val write = IO(new Write)

  val memory = Mem(32, UInt(8.W))
  style match {
    case Style.Inline => loadMemoryFromFile(memory, "mem1.txt")
    case Style.Outline => loadMemoryFromFileInline(memory, "mem2.txt")
  }

  read.data := DontCare
  when(read.en) {
    read.data := memory.read(read.addr)
  }

  when(write.en) {
    memory.write(write.addr, write.data)
  }
}

object Main extends App {
  println(
    circt.stage.ChiselStage.emitSystemVerilog(
      new Foo(Style.Outline),
      Array.empty,
      Array("-disable-all-randomization")
    )
  )

  println(
    circt.stage.ChiselStage.emitSystemVerilog(
      new Foo(Style.Inline),
      Array.empty,
      Array("-disable-all-randomization")
    )
  )
}
```

With this PR, this will produce the following two Verilog files. (You can run this with `scala-cli Foo.scala`.).

This is the `loadMemoryFromFileInline` variant:
```verilog
module memory_combMem(  
  input  [4:0] R0_addr,
  input        R0_en,
               R0_clk,
  input  [4:0] W0_addr,
  input        W0_en,
               W0_clk,
  input  [7:0] W0_data,
  output [7:0] R0_data
);

  reg [7:0] Memory[0:31];       
  always @(posedge W0_clk) begin        
    if (W0_en)  
      Memory[W0_addr] <= W0_data;       
  end
  `ifndef SYNTHESIS     
    initial     
      $readmemh("mem2.txt", Memory);    
  `endif
  assign R0_data = R0_en ? Memory[R0_addr] : 8'bx;      
endmodule

module Foo(     
  input        clock,   
               reset,   
               read_en, 
  input  [4:0] read_addr,       
  input        write_en,        
  input  [7:0] write_data,      
  input  [4:0] write_addr,      
  output [7:0] read_data        
);

  memory_combMem memory_ext (   
    .R0_addr (read_addr),
    .R0_en   (read_en),
    .R0_clk  (clock),
    .W0_addr (write_addr),
    .W0_en   (write_en),
    .W0_clk  (clock),
    .W0_data (write_data),
    .R0_data (read_data)
  );
endmodule
```

This is the `loadMemoryFromFile` variant:
```verilog
module memory_combMem(
  input  [4:0] R0_addr,
  input        R0_en,
               R0_clk,
  input  [4:0] W0_addr,
  input        W0_en,
               W0_clk,
  input  [7:0] W0_data,
  output [7:0] R0_data
);

  reg [7:0] Memory[0:31];
  always @(posedge W0_clk) begin
    if (W0_en)
      Memory[W0_addr] <= W0_data;cli/LoadMemoryFromFile.scala:30:19
  end // always @(posedge)
  /* This instance is elsewhere emitted as a bind statement.
    memory_combMem_bind memory_combMem_bind ();
  */
  assign R0_data = R0_en ? Memory[R0_addr] : 8'bx;
endmodule

module memory_combMem_bind();
  initial
    $readmemh("mem1.txt", memory_combMem.Memory);
endmodule

module Foo(
  input        clock,
               reset,
               read_en,
  input  [4:0] read_addr,
  input        write_en,
  input  [7:0] write_data,
  input  [4:0] write_addr,
  output [7:0] read_data
);

  memory_combMem memory_ext (
    .R0_addr (read_addr),
    .R0_en   (read_en),
    .R0_clk  (clock),
    .W0_addr (write_addr),
    .W0_en   (write_en),
    .W0_clk  (clock),
    .W0_data (write_data),
    .R0_data (read_data)
  );
endmodule


// ----- 8< ----- FILE "bindfile" ----- 8< -----

bind memory_combMem memory_combMem_bind memory_combMem_bind ();
```
